        var result = HtmlToMarkdownConverter.Convert(html);
        var content = result.Content ?? "";

        Assert.False(string.IsNullOrWhiteSpace(content));
        Assert.Contains("H", content);
        Assert.Contains("2", content);
        Assert.Contains("O", content);
        Assert.Contains("E=mc", content);
    }

    /// <summary>
    /// Simple table with header
    /// </summary>
    [Fact]
    public void TestSimpleTable()
    {
        var html = "<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>";
        var result = HtmlToMarkdownConverter.Convert(html);
        var content = result.Content ?? "";

        Assert.Contains("Name", content);
        Assert.Contains("Age", content);
        Assert.Contains("Alice", content);
        Assert.Contains("30", content);
        Assert.Contains("|", content);
        Assert.Contains("---", content);
    }

    /// <summary>
